        let expected_im = Math.exp(1) * Math.sin(Math.PI / 2);
        assert.approximately(result.re, expected_re, 1e-10, 'Real part calculation');
        assert.approximately(result.im, expected_im, 1e-10, 'Imaginary part calculation');
        done();
    });

    it('test exp of negative real number', function(done) {
