        assert.approximately(result.im, 0, 1e-10, 'Imaginary part should be 0');
        done();
    });
});

// Helper function for floating point comparison
assert.approximately = function(actual, expected, tolerance, message) {
    if (Math.abs(actual - expected) > tolerance) {
        throw new Error(message + `: expected ${expected}, got ${actual}, tolerance ${tolerance}`);
    }
};
